class Solution:
    def minSwaps(self, nums):
        n = len(nums)
        ones = sum(nums)
        if ones == 0 or ones == n:
            return 0
        best = 0
        for start in range(n):
            cnt = 0
            for k in range(ones):
                idx = (start + k) % n
                cnt += nums[idx]
            if cnt > best:
                best = cnt
        return ones - best

