class Solution:
    def minSwaps(self, nums):
        n = len(nums)
        ones = sum(nums)
        if ones == 0 or ones == n:
            return 0
        ext = nums + nums
        window = sum(ext[0:ones])
        best = window
        for start in range(1, n):
            window += ext[start + ones - 1] - ext[start - 1]
            if window > best:
                best = window
        return ones - best

