var minSwaps = function(nums) {
    const n = nums.length;
    let ones = 0;
    for (const x of nums) ones += x;
    if (ones === 0 || ones === n) return 0;
    const ext = nums.concat(nums);
    let window = 0;
    for (let i = 0; i < ones; i++) window += ext[i];
    let best = window;
    for (let start = 1; start < n; start++) {
        window += ext[start + ones - 1] - ext[start - 1];
        if (window > best) best = window;
    }
    return ones - best;
};
